import{_ as t,o as e,c as o,a2 as r}from"./chunks/framework.Crpw6aS5.js";const s=JSON.parse('{"title":"雅各布·哈帕兹","description":"","frontmatter":{"title":"雅各布·哈帕兹"},"headers":[],"relativePath":"04_people/雅各布·哈帕兹.md","filePath":"04_people/雅各布·哈帕兹.md"}'),l={name:"04_people/雅各布·哈帕兹.md"};function h(d,a,i,n,u,c){return e(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="雅各布·哈帕兹-jacob-harpaz" tabindex="-1">雅各布·哈帕兹（Jacob Harpaz） <a class="header-anchor" href="#雅各布·哈帕兹-jacob-harpaz" aria-label="Permalink to &quot;雅各布·哈帕兹（Jacob Harpaz）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>姓名</strong></td><td>Jacob Harpaz（雅各布·哈帕兹）</td></tr><tr><td><strong>职位</strong></td><td>ISCAR CEO</td></tr><tr><td><strong>关联公司</strong></td><td>ISCAR（伊斯卡金属切削集团）</td></tr><tr><td><strong>首次提及</strong></td><td>2006年</td></tr></tbody></table><h2 id="与巴菲特的故事" tabindex="-1">与巴菲特的故事 <a class="header-anchor" href="#与巴菲特的故事" aria-label="Permalink to &quot;与巴菲特的故事&quot;">​</a></h2><p>雅各布·哈帕兹是ISCAR的首席执行官，与董事长埃坦·韦特海默一起被巴菲特称为&quot;管理魔术师&quot;和&quot;杰出战略家&quot;。</p><h3 id="初次见面" tabindex="-1">初次见面 <a class="header-anchor" href="#初次见面" aria-label="Permalink to &quot;初次见面&quot;">​</a></h3><p>2005年11月，埃坦·韦特海默带着雅各布和首席财务官丹尼·戈德曼来到奥马哈与巴菲特会面：</p><blockquote><p>&quot;与他们相处了几个小时后，我确信如果我们达成交易，我们将与非凡的管理人才合作，他们可以在出售后以与之前相同的精力和奉献精神经营业务。&quot;（2006年股东信）</p></blockquote><h3 id="管理魔术师" tabindex="-1">&quot;管理魔术师&quot; <a class="header-anchor" href="#管理魔术师" aria-label="Permalink to &quot;&quot;管理魔术师&quot;&quot;">​</a></h3><p>巴菲特如此描述ISCAR的管理团队：</p><blockquote><p>&quot;ISCAR的产品是小型可消耗切削工具，与大型昂贵的机床配合使用。这是一项没有魔法的业务，除了运营者赋予的魔法。但埃坦、雅各布和他们的同事是真正的管理魔术师，不断开发工具使其客户的机器更具生产力。结果是：ISCAR赚钱，因为它能让客户赚更多钱。没有比这更好的持续成功配方了。&quot;（2006年股东信）</p></blockquote><h3 id="持续增长" tabindex="-1">持续增长 <a class="header-anchor" href="#持续增长" aria-label="Permalink to &quot;持续增长&quot;">​</a></h3><p>ISCAR在收购后业绩远超预期，巴菲特在2007年股东信中再次强调：</p><blockquote><p>&quot;Iscar是我见过最令人印象深刻的制造企业，我去年就这么说过，今年秋天我参观了它在韩国令人惊叹的工厂，这个看法得到了验证。&quot;（2007年股东信）</p></blockquote><h3 id="逆势收购" tabindex="-1">逆势收购 <a class="header-anchor" href="#逆势收购" aria-label="Permalink to &quot;逆势收购&quot;">​</a></h3><p>2008年金融危机期间，雅各布与团队逆势收购了日本领先的切削工具制造商Tungaloy：</p><blockquote><p>&quot;当2008年11月经济世界崩溃时，他们挺身而出收购了Tungaloy……去年春天海啸袭击东京北部时，Tungaloy遭受了重大损失。但你现在不会知道：Tungaloy在2011年创下了销售纪录。&quot;（2011年股东信）</p></blockquote><h3 id="中国战略" tabindex="-1">中国战略 <a class="header-anchor" href="#中国战略" aria-label="Permalink to &quot;中国战略&quot;">​</a></h3><p>ISCAR还在中国大连开设了大工厂，将生产基地搬到钨的原产地，展现了前瞻性的全球布局能力。</p><h2 id="关联年份" tabindex="-1">关联年份 <a class="header-anchor" href="#关联年份" aria-label="Permalink to &quot;关联年份&quot;">​</a></h2><p>2005, 2006, 2007, 2008, 2010, 2011</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./../03_公司库/ISCAR.html">ISCAR</a> - 管理的公司</li><li><a href="./埃坦·韦特海默.html">埃坦·韦特海默</a> - 董事长搭档</li><li><a href="./../03_公司库/伯克希尔哈撒韦.html">伯克希尔·哈撒韦</a> - 母公司</li></ul><hr><p><em>最后更新：2026-04-09</em></p>',25)])])}const q=t(l,[["render",h]]);export{s as __pageData,q as default};
